import{_ as e,o as d,c as o,ag as i}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Alias Git | Dotfiles (IT)","titleTemplate":":title","description":"Oltre 80 alias shell Git per velocizzare commit, branch, diff, remoti e flussi di lavoro sottomoduli. Scorciatoie Git per Bash e Zsh.","frontmatter":{"title":"Alias Git | Dotfiles","description":"Oltre 80 alias shell Git per velocizzare commit, branch, diff, remoti e flussi di lavoro sottomoduli. Scorciatoie Git per Bash e Zsh.","lang":"it-IT","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Git preview","canonical":"/it/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Git","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Git - Dotfiles (IT)","permalink":"/it/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"alias git, scorciatoie git, dotfiles git, alias commit git, alias branch git, alias push git, shell, bash, zsh"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Oltre 80 alias shell Git per velocizzare commit, branch, diff, remoti e flussi di lavoro sottomoduli."},{"name":"twitter:title","content":"Alias Git - Dotfiles"},{"name":"og:title","content":"Alias Git - Dotfiles"},{"name":"og:description","content":"Oltre 80 alias shell Git per velocizzare commit, branch, diff, remoti e flussi di lavoro sottomoduli."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"it_IT"}]},"headers":[],"relativePath":"it/aliases/git/index.md","filePath":"it/aliases/git/index.md","lastUpdated":1773010926000}'),a={name:"it/aliases/git/index.md"};function r(c,t,l,s,n,h){return d(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="alias-git" tabindex="-1">Alias Git <a class="header-anchor" href="#alias-git" aria-label="Permalink to &quot;Alias Git&quot;">​</a></h1><p>Alias shell Git che creano scorciatoie per i comandi Git usati frequentemente.</p><h2 id="panoramica" tabindex="-1">Panoramica <a class="header-anchor" href="#panoramica" aria-label="Permalink to &quot;Panoramica&quot;">​</a></h2><p>Questi alias sono definiti in <code>git.aliases.sh</code> e <code>signing.aliases.sh</code> e caricati automaticamente da Chezmoi. Sono disponibili in qualsiasi sessione Bash o Zsh una volta installati.</p><h2 id="riferimento" tabindex="-1">Riferimento <a class="header-anchor" href="#riferimento" aria-label="Permalink to &quot;Riferimento&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>g</code></td><td><code>git</code></td><td>Abbreviazione per git</td></tr><tr><td><code>gtp</code></td><td><code>git rev-parse --show-toplevel</code></td><td>Stampa la directory di livello superiore del repository</td></tr><tr><td><code>grpa</code></td><td><code>git rev-parse --abbrev-ref HEAD</code></td><td>Stampa il nome del branch corrente</td></tr><tr><td><code>gconfl</code></td><td><code>git config --list</code></td><td>Elenca tutte le impostazioni di configurazione Git</td></tr></tbody></table><h3 id="area-di-lavoro" tabindex="-1">Area di lavoro <a class="header-anchor" href="#area-di-lavoro" aria-label="Permalink to &quot;Area di lavoro&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>ga</code></td><td><code>git add</code></td><td>Metti in staging i file</td></tr><tr><td><code>gaa</code></td><td><code>git add --all</code></td><td>Metti in staging tutte le modifiche</td></tr><tr><td><code>gad</code></td><td><code>git add .</code></td><td>Metti in staging tutto nella directory corrente</td></tr><tr><td><code>gcl</code></td><td><code>git clone</code></td><td>Clona un repository</td></tr><tr><td><code>gin</code></td><td><code>git init</code></td><td>Inizializza un nuovo repository Git</td></tr><tr><td><code>gco</code></td><td><code>git checkout</code></td><td>Cambia branch o ripristina file</td></tr><tr><td><code>gcb</code></td><td><code>git checkout -b</code></td><td>Crea e passa a un nuovo branch</td></tr><tr><td><code>gst</code></td><td><code>git status</code></td><td>Mostra lo stato dell&#39;albero di lavoro</td></tr><tr><td><code>gsta</code></td><td><code>git stash save</code></td><td>Nascondi le modifiche correnti</td></tr><tr><td><code>gstp</code></td><td><code>git stash pop</code></td><td>Applica e rimuovi l&#39;ultima stash</td></tr></tbody></table><h3 id="commit" tabindex="-1">Commit <a class="header-anchor" href="#commit" aria-label="Permalink to &quot;Commit&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>gc</code></td><td><code>git commit -a</code></td><td>Esegui commit di tutte le modifiche tracciate</td></tr><tr><td><code>gca</code></td><td><code>git commit --amend</code></td><td>Modifica l&#39;ultimo commit</td></tr><tr><td><code>gcm</code></td><td><code>git commit --message</code></td><td>Esegui commit con un messaggio in linea</td></tr><tr><td><code>gcane</code></td><td><code>git commit --amend --no-edit</code></td><td>Modifica commit senza cambiare messaggio</td></tr></tbody></table><h3 id="diff-e-cronologia" tabindex="-1">Diff e cronologia <a class="header-anchor" href="#diff-e-cronologia" aria-label="Permalink to &quot;Diff e cronologia&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>gd</code></td><td><code>git diff</code></td><td>Mostra le modifiche non in staging</td></tr><tr><td><code>gdstaged</code></td><td><code>git diff --staged</code></td><td>Mostra le modifiche in staging</td></tr><tr><td><code>gl</code></td><td><code>git log --since=&quot;last month&quot; --oneline</code></td><td>Log su una riga dell&#39;ultimo mese</td></tr><tr><td><code>glg</code></td><td><code>git log --graph --all --oneline --decorate</code></td><td>Log grafico di tutti i branch</td></tr></tbody></table><h3 id="branch" tabindex="-1">Branch <a class="header-anchor" href="#branch" aria-label="Permalink to &quot;Branch&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>gb</code></td><td><code>git branch</code></td><td>Elenca i branch locali</td></tr><tr><td><code>gbd</code></td><td><code>git branch -d</code></td><td>Elimina un branch unito</td></tr><tr><td><code>gbr</code></td><td><code>git branch -r</code></td><td>Elenca i branch remoti</td></tr><tr><td><code>gswb</code></td><td><code>git switch</code></td><td>Cambia branch (moderno)</td></tr></tbody></table><h3 id="remoti-e-push-pull" tabindex="-1">Remoti e push/pull <a class="header-anchor" href="#remoti-e-push-pull" aria-label="Permalink to &quot;Remoti e push/pull&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>gf</code></td><td><code>git fetch</code></td><td>Recupera dal remoto</td></tr><tr><td><code>gp</code></td><td><code>git pull</code></td><td>Esegui pull dal remoto</td></tr><tr><td><code>gph</code></td><td><code>git push</code></td><td>Esegui push sul remoto</td></tr><tr><td><code>gpo</code></td><td><code>git push origin</code></td><td>Esegui push sull&#39;origine</td></tr><tr><td><code>gr</code></td><td><code>git remote</code></td><td>Gestisci i remoti</td></tr><tr><td><code>grv</code></td><td><code>git remote -v</code></td><td>Mostra gli URL remoti</td></tr></tbody></table><h3 id="annulla-e-reset" tabindex="-1">Annulla e reset <a class="header-anchor" href="#annulla-e-reset" aria-label="Permalink to &quot;Annulla e reset&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>grev</code></td><td><code>git revert</code></td><td>Annulla un commit</td></tr><tr><td><code>grb</code></td><td><code>git rebase</code></td><td>Rebase del branch corrente</td></tr><tr><td><code>gresh</code></td><td><code>git reset --hard HEAD~1</code></td><td>Hard reset al commit precedente</td></tr><tr><td><code>gress</code></td><td><code>git reset --soft HEAD~1</code></td><td>Soft reset (mantieni modifiche in staging)</td></tr></tbody></table><h3 id="sottomoduli" tabindex="-1">Sottomoduli <a class="header-anchor" href="#sottomoduli" aria-label="Permalink to &quot;Sottomoduli&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>gsm</code></td><td><code>git submodule</code></td><td>Gestisci sottomoduli</td></tr><tr><td><code>gsmi</code></td><td><code>git submodule init</code></td><td>Inizializza sottomoduli</td></tr><tr><td><code>gsmu</code></td><td><code>git submodule update</code></td><td>Aggiorna sottomoduli</td></tr><tr><td><code>gsmuir</code></td><td><code>git submodule update --init --recursive</code></td><td>Aggiorna, inizializza e ricorsivamente i sottomoduli</td></tr></tbody></table><h3 id="firma-e-sicurezza" tabindex="-1">Firma e sicurezza <a class="header-anchor" href="#firma-e-sicurezza" aria-label="Permalink to &quot;Firma e sicurezza&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>enable-signing</code></td><td>Configura la firma GPG o SSH dei commit</td></tr><tr><td><code>verify-signatures</code></td><td>Verifica le firme degli ultimi 10 commit</td></tr><tr><td><code>check-signing</code></td><td>Controlla la configurazione di firma corrente</td></tr></tbody></table>',23)])])}const u=e(a,[["render",r]]);export{g as __pageData,u as default};
